// // This module decrements the 4-bit counter on each positive edge of the clock signal and resets to 15 when RESET is high.
module counter_4bit (CLK, RESET, Q);
input CLK, RESET;
output reg [3:0] Q;

always @(posedge CLK or posedge RESET) begin
    if (RESET)
        Q <= 4'b0000;
    else
        Q <= Q + 1;
end

endmodule
